// src/components/TelaEsterilizacao.jsx
import React, { useState, useEffect } from 'react'
import axios from 'axios'
import { toast } from 'react-toastify'

export default function TelaEsterilizacao() {
  const [codigo, setCodigo] = useState('')
  const [caixa, setCaixa]   = useState(null)
  const [alunoPin, setAlunoPin] = useState('')
  const [historico, setHistorico] = useState([])

  useEffect(() => {
    if (!caixa) return
    axios
      .get(`/api/movimentacoes/caixa/${caixa.id}`)
      .then(res => setHistorico(res.data))
      .catch(() => setHistorico([]))
  }, [caixa])

  const buscarCaixa = async () => {
    try {
      const res = await axios.get(`/api/caixas/codigo/${codigo}`)
      setCaixa(res.data)
      toast.success(`Caixa encontrada: ${res.data.nome}`)
    } catch {
      toast.error('Caixa não encontrada.')
      setCaixa(null)
      setHistorico([])
    }
  }

  const operar = async (tipo) => {
    if (!caixa) return toast.warn('Busque uma caixa primeiro.')
    if (!alunoPin) return toast.warn('Informe o PIN do aluno.')

    try {
      await axios.post(`/api/movimentacoes/${tipo}`, {
        caixa_id: caixa.id,
        aluno_pin: alunoPin
      })
      toast.success(`${tipo === 'entrada' ? 'Entrada' : 'Saída'} registrada!`)
      const res = await axios.get(`/api/movimentacoes/caixa/${caixa.id}`)
      setHistorico(res.data)
    } catch {
      toast.error(`Erro ao registrar ${tipo}.`)
    }
  }

  return (
    <div className="max-w-3xl mx-auto py-10 px-4 space-y-6">
      <h2 className="text-2xl font-bold">Controle de Esterilização</h2>

      {/* Busca da caixa */}
      <div className="bg-white rounded-2xl shadow p-6">
        <div className="flex flex-col md:flex-row gap-4">
          <input
            type="text"
            placeholder="Código de barras"
            value={codigo}
            onChange={e => setCodigo(e.target.value)}
            className="flex-1 border rounded px-3 py-2"
          />
          <button
            onClick={buscarCaixa}
            className="w-full md:w-auto bg-blue-600 hover:bg-blue-700 text-white font-bold px-4 py-2 rounded-full"
          >
            Buscar
          </button>
        </div>
      </div>

      {/* Dados da caixa */}
      {caixa && (
        <div className="bg-white rounded-2xl shadow p-6">
          <p><strong>ID:</strong> {caixa.id}</p>
          <p><strong>Nome:</strong> {caixa.nome}</p>
        </div>
      )}

      {/* Operação */}
      {caixa && (
        <div className="bg-white rounded-2xl shadow p-6">
          <div className="flex flex-col md:flex-row gap-4">
            <input
              type="text"
              placeholder="PIN do aluno"
              value={alunoPin}
              onChange={e => setAlunoPin(e.target.value.replace(/\D/g,'').slice(0,4))}
              className="flex-1 border rounded px-3 py-2"
            />
            <button
              onClick={() => operar('entrada')}
              className="w-full md:w-auto bg-green-600 hover:bg-green-700 text-white font-bold px-4 py-2 rounded-full"
            >
              Entrada
            </button>
            <button
              onClick={() => operar('saida')}
              className="w-full md:w-auto bg-red-600 hover:bg-red-700 text-white font-bold px-4 py-2 rounded-full"
            >
              Saída
            </button>
          </div>
        </div>
      )}

      {/* Histórico */}
      {caixa && (
        <div className="bg-white rounded-2xl shadow p-6">
          <h3 className="text-xl font-bold mb-4">Histórico</h3>
          {historico.length > 0 ? (
            <div className="overflow-x-auto">
              <table className="min-w-full table-auto text-sm">
                <thead>
                  <tr className="bg-gray-100">
                    <th className="p-2 text-left">Tipo</th>
                    <th className="p-2 text-left">Aluno</th>
                    <th className="p-2 text-left">Operador</th>
                    <th className="p-2 text-left">Data</th>
                  </tr>
                </thead>
                <tbody>
                  {historico.map(m => (
                    <tr key={m.id} className="hover:bg-gray-50">
                      <td className="p-2">{m.tipo}</td>
                      <td className="p-2">{m.alunoNome}</td>
                      <td className="p-2">{m.operadorNome}</td>
                      <td className="p-2">
                        {new Date(m.criado_em).toLocaleString()}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          ) : (
            <p className="text-gray-500">Nenhuma movimentação registrada.</p>
          )}
        </div>
      )}
    </div>
  )
}
